import\('./src/config/database.js'\).then\(async \({ pool }\) => {
  try {
    // mst_post의 user_nm과 mst_influencer의 profile_nm 매칭
    const matched = await pool.query\(\\"SELECT COUNT\(DISTINCT A.profile_id\) as cnt FROM fnco_influencer.mst_influencer A INNER JOIN fnco_influencer.mst_post B ON LOWER\(TRIM\(A.profile_nm\)\) = LOWER\(TRIM\(B.user_nm\)\)\\"\);
    console.log\('시딩 콘텐츠 매칭 인플루언서:', matched.rows[0].cnt\);

    // 상세 확인
    const detail = await pool.query\(\\"SELECT A.profile_id, A.profile_nm, B.user_nm, B.seeding_product, B.platform FROM fnco_influencer.mst_influencer A INNER JOIN fnco_influencer.mst_post B ON LOWER\(TRIM\(A.profile_nm\)\) = LOWER\(TRIM\(B.user_nm\)\) LIMIT 10\\"\);
    console.log\('매칭 상세:', detail.rows\);

    // profile_url 기반 매칭도 시도
    const urlMatch = await pool.query\(\\"SELECT COUNT\(DISTINCT A.profile_id\) as cnt FROM fnco_influencer.mst_influencer A INNER JOIN fnco_influencer.mst_post B ON A.profile_url ILIKE '%' || B.user_id || '%' WHERE B.user_id IS NOT NULL AND B.user_id != ''\\"\);
    console.log\('URL기반 매칭:', urlMatch.rows[0].cnt\);
  } catch\(e\) { console.error\(e.message\); }
  finally { process.exit\(0\); }
}\).catch\(e => console.error\(e.message\)\);
" 2>&1)

